		Short: "Import a context from a tar or zip file",
		Args:  cli.ExactArgs(2),
		RunE: func(cmd *cobra.Command, args []string) error {
			return runImport(dockerCLI, args[0], args[1])
		},
		// TODO(thaJeztah): this should also include "-"
